      "term": "SI Units",
      "simpleDefinition": "The international system of standard measurements used to ensure everyone in science and engineering uses the same 'language'.",
      "anchor": "The global rulebook for measurement.",
      "misconception": "Thinking that different countries use different electrical units; SI units are universal in the industry."
    },
    {
      "term": "Base Units",
      "simpleDefinition": "The seven fundamental units that aren't made from other units, such as the Metre (length), Kilogram (mass), and Second (time).",
      "anchor": "The building blocks of all measurement.",
      "misconception": "Believing that complex units like Watts or Volts are base units; they are actually built from base units."
    },
    {
      "term": "Derived Units",
      "simpleDefinition": "Units created by combining base units, such as Area (square metres) or Velocity (metres per second).",
      "anchor": "Units made by mixing base units together.",
      "misconception": "Thinking derived units are less accurate or 'unofficial' compared to base units."
    },
    {
      "term": "Voltage (Volt)",
      "simpleDefinition": "The electrical pressure or potential difference that pushes charge through a circuit.",
      "anchor": "The 'push' in the circuit.",
      "misconception": "Thinking voltage 'flows' through a wire; voltage is the pressure, current is the flow."
    },
    {
      "term": "Current (Ampere)",
      "simpleDefinition": "The rate of flow of electric charge, measured in Amps.",
      "anchor": "The 'flow' of electricity.",
      "misconception": "Confusing the amount of flow (Amps) with the pressure (Volts)."
    },
    {
      "term": "Resistance (Ohm)",
